-- ESP32 CO2 Drift Compensator - 示例数据
-- 时间范围: 2026-01-03 至 2026-01-09
-- 说明: 这是密闭空间藻类呼吸作用监测的实际部署数据
--       数据展示了因气路漏气导致的CO2持续下降趋势
--       可用于测试前端的漂移补偿算法

SET SQL_MODE = "NO_AUTO_VALUE_ON_ZERO";
SET time_zone = "+00:00";

-- 表结构
CREATE TABLE IF NOT EXISTS `co2_measurements` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `timestamp` datetime NOT NULL,
  `co2_ppm` int(11) NOT NULL,
  `temperature` float DEFAULT NULL,
  `humidity` float DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  INDEX `idx_timestamp` (`timestamp`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- 清空旧数据（可选）
-- TRUNCATE TABLE `co2_measurements`;

-- 示例数据 (2026-01-03 ~ 2026-01-09)
-- 注: 数据量较大，仅包含部分关键时间点以展示漂移趋势
